// EmployeeManagementServiceImpl.java (Service Implementation)
package com.hr.service;

import com.hr.data.EmployeeDataStore;
import com.hr.model.*;

import javax.jws.WebService;
import java.util.ArrayList;
import java.util.Date;
import java.util.List;
import java.util.logging.Level;
import java.util.logging.Logger;
import java.util.stream.Collectors;

@WebService(
    endpointInterface = "com.hr.service.EmployeeManagementService",
    serviceName = "EmployeeManagementService",
    portName = "EmployeeManagementPort",
    targetNamespace = "http://service.hr.com/employee",
    wsdlLocation = "EmployeeManagementService.wsdl"
)
public class EmployeeManagementServiceImpl implements EmployeeManagementService {

    private static final Logger LOGGER = Logger.getLogger(EmployeeManagementServiceImpl.class.getName());
    private static final double MAX_RAISE_PERCENTAGE = 50.0;
    private static final double MAX_SALARY = 500000.0;
    private static final double MIN_SALARY = 30000.0;

    private final EmployeeDataStore dataStore = EmployeeDataStore.getInstance();

    @Override
    public Employee getEmployee(int employeeId) {
        LOGGER.info("Fetching employee with ID: " + employeeId);
        Employee employee = dataStore.getEmployee(employeeId);
        if (employee == null) {
            LOGGER.warning("Employee not found with ID: " + employeeId);
        }
        return employee;
    }

    @Override
    public List<Employee> getAllActiveEmployees() {
        LOGGER.info("Fetching all active employees");
        return dataStore.getActiveEmployees();
    }

    @Override
    public List<Employee> getEmployeesByDepartment(String department) {
        LOGGER.info("Fetching employees for department: " + department);
        if (department == null || department.trim().isEmpty()) {
            return new ArrayList<>();
        }
        return dataStore.getActiveEmployees().stream()
                .filter(e -> department.equalsIgnoreCase(e.getDepartment()))
                .collect(Collectors.toList());
    }

    @Override
    public SalaryUpdateResult updateSalary(int employeeId, double newSalary, String reason, String approvedBy) {
        LOGGER.info(String.format("Salary update request - Employee: %d, New Salary: %.2f, Approved by: %s",
                employeeId, newSalary, approvedBy));

        Employee employee = dataStore.getEmployee(employeeId);
        if (employee == null) {
            return new SalaryUpdateResult(false, "Employee not found with ID: " + employeeId, employeeId, 0, 0);
        }

        if (!"ACTIVE".equals(employee.getStatus())) {
            return new SalaryUpdateResult(false, "Cannot update salary for inactive employee", 
                    employeeId, employee.getSalary(), employee.getSalary());
        }

        if (newSalary < MIN_SALARY || newSalary > MAX_SALARY) {
            return new SalaryUpdateResult(false, 
                    String.format("Salary must be between %.2f and %.2f", MIN_SALARY, MAX_SALARY),
                    employeeId, employee.getSalary(), employee.getSalary());
        }

        if (reason == null || reason.trim().isEmpty()) {
            return new SalaryUpdateResult(false, "Reason for salary update is required",
                    employeeId, employee.getSalary(), employee.getSalary());
        }

        if (approvedBy == null || approvedBy.trim().isEmpty()) {
            return new SalaryUpdateResult(false, "Approver information is required",
                    employeeId, employee.getSalary(), employee.getSalary());
        }

        double previousSalary = employee.getSalary();
        employee.setSalary(newSalary);
        dataStore.updateEmployee(employee);

        LOGGER.info(String.format("Salary updated for employee %d: %.2f -> %.2f (Reason: %s, Approved by: %s)",
                employeeId, previousSalary, newSalary, reason, approvedBy));

        return new SalaryUpdateResult(true, 
                "Salary updated successfully for " + employee.getFirstName() + " " + employee.getLastName(),
                employeeId, previousSalary, newSalary);
    }

    @Override
    public SalaryUpdateResult applyRaise(int employeeId, double raisePercentage, String reason, String approvedBy) {
        LOGGER.info(String.format("Raise request - Employee: %d, Percentage: %.2f%%", employeeId, raisePercentage));

        Employee employee = dataStore.getEmployee(employeeId);
        if (employee == null) {
            return new SalaryUpdateResult(false, "Employee not found with ID: " + employeeId, employeeId, 0, 0);
        }

        if (raisePercentage <= 0 || raisePercentage > MAX_RAISE_PERCENTAGE) {
            return new SalaryUpdateResult(false, 
                    String.format("Raise percentage must be between 0 and %.0f%%", MAX_RAISE_PERCENTAGE),
                    employeeId, employee.getSalary(), employee.getSalary());
        }

        double newSalary = employee.getSalary() * (1 + raisePercentage / 100.0);
        return updateSalary(employeeId, Math.round(newSalary * 100.0) / 100.0, reason, approvedBy);
    }

    @Override
    public List<SalaryUpdateResult> applyBulkRaise(String department, double raisePercentage, String approvedBy) {
        LOGGER.info(String.format("Bulk raise request - Department: %s, Percentage: %.2f%%", department, raisePercentage));

        List<SalaryUpdateResult> results = new ArrayList<>();
        List<Employee> departmentEmployees = getEmployeesByDepartment(department);

        if (departmentEmployees.isEmpty()) {
            SalaryUpdateResult noEmployees = new SalaryUpdateResult();
            noEmployees.setSuccess(false);
            noEmployees.setMessage("No active employees found in department: " + department);
            results.add(noEmployees);
            return results;
        }

        for (Employee employee : departmentEmployees) {
            SalaryUpdateResult result = applyRaise(employee.getEmployeeId(), raisePercentage,
                    "Bulk department raise for " + department, approvedBy);
            results.add(result);
        }

        return results;
    }

    @Override
    public ServiceResponse submitPerformanceReview(PerformanceReview review) {
        LOGGER.info("Submitting performance review for employee: " + review.getEmployeeId());

        if (review == null) {
            return new ServiceResponse(false, "Review data is required", "INVALID_INPUT");
        }

        Employee employee = dataStore.getEmployee(review.getEmployeeId());
        if (employee == null) {
            return new ServiceResponse(false, "Employee not found with ID: " + review.getEmployeeId(), "EMPLOYEE_NOT_FOUND");
        }

        if (!"ACTIVE".equals(employee.getStatus())) {
            return new ServiceResponse(false, "Cannot submit review for inactive employee", "INACTIVE_EMPLOYEE");
        }

        if (review.getRating() < 1 || review.getRating() > 5) {
            return new ServiceResponse(false, "Rating must be between 1 and 5", "INVALID_RATING");
        }

        if (review.getReviewerName() == null || review.getReviewerName().trim().isEmpty()) {
            return new ServiceResponse(false, "Reviewer name is required", "MISSING_REVIEWER");
        }

        if (review.getComments() == null || review.getComments().trim().isEmpty()) {
            return new ServiceResponse(false, "Review comments are required", "MISSING_COMMENTS");
        }

        if (review.getReviewDate() == null) {
            review.setReviewDate(new Date());
        }

        // Set overall assessment based on rating
        switch (review.getRating()) {
            case 5: review.setOverallAssessment("EXCEPTIONAL"); break;
            case 4: review.setOverallAssessment("EXCEEDS_EXPECTATIONS"); break;
            case 3: review.setOverallAssessment("MEETS_EXPECTATIONS"); break;
            case 2: review.setOverallAssessment("NEEDS_IMPROVEMENT"); break;
            case 1: review.setOverallAssessment("UNSATISFACTORY"); break;
        }

        dataStore.addReview(review);

        LOGGER.info(String.format("Performance review submitted for employee %d by %s - Rating: %d",
                review.getEmployeeId(), review.getReviewerName(), review.getRating()));

        return new ServiceResponse(true, 
                String.format("Performance review submitted successfully for %s %s. Review ID: %d",
                        employee.getFirstName(), employee.getLastName(), review.getReviewId()));
    }

    @Override
    public List<PerformanceReview> getPerformanceReviews(int employeeId) {
        LOGGER.info("Fetching performance reviews for employee: " + employeeId);
        return dataStore.getReviews(employeeId);
    }

    @Override
    public PerformanceReview getLatestPerformanceReview(int employeeId) {
        LOGGER.info("Fetching latest performance review for employee: " + employeeId);
        return dataStore.getLatestReview(employeeId);
    }

    @Override
    public TerminationResult terminateEmployee(int employeeId, String reason, String processedBy) {
        LOGGER.info(String.format("Termination request - Employee: %d, Reason: %s, Processed by: %s",
                employeeId, reason, processedBy));

        TerminationResult result = new TerminationResult();
        result.setEmployeeId(employeeId);

        Employee employee = dataStore.getEmployee(employeeId);
        if (employee == null) {
            result.setSuccess(false);
            result.setMessage("Employee not found with ID: " + employeeId);
            return result;
        }

        if ("TERMINATED".equals(employee.getStatus())) {
            result.setSuccess(false);
            result.setMessage("Employee is already terminated");
            result.setEmployeeName(employee.getFirstName() + " " + employee.getLastName());
            return result;
        }

        if (reason == null || reason.trim().isEmpty()) {
            result.setSuccess(false);
            result.setMessage("Termination reason is required");
            return result;
        }

        if (processedBy == null || processedBy.trim().isEmpty()) {
            result.setSuccess(false);
            result.setMessage("Processor information is required");
            return result;
        }

        Date terminationDate = new Date();
        
        // Calculate final pay (prorated monthly salary + any remaining balance)
        double finalPay = employee.getSalary() / 12.0; // One month's pay as final settlement

        employee.setStatus("TERMINATED");
        employee.setTerminationDate(terminationDate);
        employee.setTerminationReason(reason);
        dataStore.updateEmployee(employee);

        result.setSuccess(true);
        result.setMessage(String.format("Employee %s %s has been terminated successfully",
                employee.getFirstName(), employee.getLastName()));
        result.setEmployeeName(employee.getFirstName() + " " + employee.getLastName());
        result.setTerminationDate(terminationDate);
        result.setTerminationReason(reason);
        result.setFinalPayAmount(Math.round(finalPay * 100.0) / 100.0);

        LOGGER.info(String.format("Employee %d terminated. Final pay: %.2f", employeeId, finalPay));

        return result;
    }

    @Override
    public ServiceResponse reinstateEmployee(int employeeId, String processedBy) {
        LOGGER.info(String.format("Reinstatement request - Employee: %d, Processed by: %s", employeeId, processedBy));

        Employee employee = dataStore.getEmployee(employeeId);
        if (employee == null) {
            return new ServiceResponse(false, "Employee not found with ID: " + employeeId, "EMPLOYEE_NOT_FOUND");
        }

        if ("ACTIVE".equals(employee.getStatus())) {
            return new ServiceResponse(false, "Employee is already active", "ALREADY_ACTIVE");
        }

        if (processedBy == null || processedBy.trim().isEmpty()) {
            return new ServiceResponse(false, "Processor information is required", "MISSING_PROCESSOR");
        }

        employee.setStatus("ACTIVE");
        employee.setTerminationDate(null);
        employee.setTerminationReason(null);
        dataStore.updateEmployee(employee);

        LOGGER.info(String.format("Employee %d reinstated by %s", employeeId, processedBy));

        return new ServiceResponse(true, 
                String.format("Employee %s %s has been reinstated successfully",
                        employee.getFirstName(), employee.getLastName()));
    }
}

// EmployeeManagementServicePublisher.java
package com.hr;

import com.hr.service.EmployeeManagementServiceImpl;

import javax.xml.ws.Endpoint;
import java.util.logging.Logger;

public class EmployeeManagementServicePublisher {

    private static final Logger LOGGER = Logger.getLogger(EmployeeManagementServicePublisher.class.getName());
    private static final String SERVICE_URL = "http://localhost:8080/hr/employee-management";

    public static void main(String[] args) {
        try {
            EmployeeManagementServiceImpl serviceImpl = new EmployeeManagementServiceImpl();
            Endpoint endpoint = Endpoint.publish(SERVICE_URL, serviceImpl);

            LOGGER.info("==============================================");
            LOGGER.info("HR Employee Management SOAP Web Service Started");
            LOGGER.info("Service URL: " + SERVICE_URL);
            LOGGER.info("WSDL URL: " + SERVICE_URL + "?wsdl");
            LOGGER.info("==============================================");

            // Add shutdown hook for graceful shutdown
            Runtime.getRuntime().addShutdownHook(new Thread(() -> {
                LOGGER.info("Shutting down Employee Management Service...");
                endpoint.stop();
                LOGGER.info("Service stopped.");
            }));

            // Keep the service running
            LOGGER.info("Press Ctrl+C to stop the service");
            Thread.currentThread().join();

        } catch (Exception e) {
            LOGGER.severe("Failed to start Employee Management Service: " + e.getMessage());
            e.printStackTrace();
        }
    }
}

